styles: [`
    @import url('https://fonts.googleapis.com/css2?family=Sora:wght@300;400;600;700;800&display=swap');

    :host { 
      display: block; 
      font-family: 'Sora', sans-serif; 
    }

    .report-page {
      position: relative;
      padding: 20px 0 60px;
      display: grid;
      gap: 48px;
    }

    .bg-blob {
      position: fixed;
      border-radius: 50%;
      filter: blur(80px);
      pointer-events: none;
      z-index: 0;
    }

    .blob-1 { 
      width: 520px; height: 520px; 
      background: radial-gradient(circle, rgba(99,102,241,0.1) 0%, transparent 70%); 
      top: -120px; left: -160px; 
    }

    .blob-2 { 
      width: 400px; height: 400px; 
      background: radial-gradient(circle, rgba(6,182,212,0.08) 0%, transparent 70%); 
      bottom: 80px; right: -100px; 
    }

    .blob-3 { 
      width: 340px; height: 340px; 
      background: radial-gradient(circle, rgba(168,85,247,0.07) 0%, transparent 70%); 
      top: 45%; left: 45%; 
    }

    .page-header, 
    .summary-grid, 
    .report-grid, 
    .global-report, 
    .actions-row {
      position: relative;
      z-index: 1;
    }

    .btn-back {
      width: 48px; height: 48px;
      background: #0f172a;
      color: white;
      border-radius: 50%;
      display: grid;
      place-items: center;
      font-size: 1.5rem;
      text-decoration: none;
      border: 1px solid #6366f1;
    }

    h1, 
    h2 { color: #ffffff; }

    .card-badge {
      background: rgba(99,102,241,0.15);
      color: #c4d0ff;
      padding: 6px 16px;
      border-radius: 999px;
      font-size: 0.75rem;
      font-weight: 700;
      text-transform: uppercase;
      letter-spacing: 1px;
    }

    .subtitle { 
      color: #e0e7ff; 
    }

    /* ---------------------- */
    /*   SUMMARY CARDS (EDIT) */
    /* ---------------------- */

    .summary-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 16px;
    }

    .summary-card {
      background: rgba(255, 255, 255, 0.06);
      border: 1px solid rgba(255, 255, 255, 0.18);
      border-radius: 18px;
      padding: 18px;
      backdrop-filter: blur(6px);
      color: white !important;          /* 🟢 texte en blanc */
    }

    .summary-card span.label {
      color: #e2e8f0 !important;        /* 🟢 sous-titres blanc-gris */
      font-size: 0.85rem;
    }

    .summary-card strong {
      color: #ffffff !important;        /* 🟢 valeurs en blanc */
      font-size: 1.1rem;
    }

    .birads-global .birads-value {
      font-weight: 800;
      font-size: 1.4rem;
      color: #ffffff !important;         /* 🟢 BI-RADS global en blanc */
    }

    /* ---------------------- */
    /*   REPORT CARDS         */
    /* ---------------------- */

    .report-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
      gap: 28px;
    }

    .report-card {
      background: rgba(15, 23, 42, 0.6);
      border: 1px solid rgba(255, 255, 255, 0.1);
      border-radius: 22px;
      padding-bottom: 16px;
      color: white;
      backdrop-filter: blur(8px);
    }

    .card-header {
      display: flex;
      justify-content: space-between;
      padding: 20px;
    }

    .view-title {
      margin: 0;
      font-weight: 700;
      color: #ffffff;
    }

    .view-subtitle {
      font-size: 0.9rem;
      color: #cbd5e1;
    }

    .badge {
      background: #facc15;
      color: #78350f;
      padding: 8px 12px;
      border-radius: 999px;
      font-weight: 700;
    }

    .card-body {
      padding: 0 20px;
      display: grid;
      gap: 20px;
    }

    .image-preview {
      min-height: 260px;
      border-radius: 16px;
      overflow: hidden;
      background: #0f172a;
      display: grid;
      place-items: center;
    }

    .image-preview img {
      width: 100%;
      height: 100%;
      object-fit: contain;
    }

    .image-placeholder {
      color: #94a3b8;
    }

    .analysis-card {
      color: #e2e8f0;
    }

    .classification {
      font-weight: 700;
      color: #ffffff;
    }

    .findings strong {
      color: #ffffff;
    }

    /* ---------------------- */
    /*  GLOBAL REPORT         */
    /* ---------------------- */

    .global-report h2 {
      color: white;
      margin-bottom: 12px;
    }

    .details-content {
      color: #e2e8f0;
      line-height: 1.6;
    }

    /* ---------------------- */
    /*  ACTION BUTTONS        */
    /* ---------------------- */

    .actions-row {
      display: flex;
      gap: 16px;
    }

    .btn-primary {
      padding: 14px 28px;
      border-radius: 999px;
      background: #6366f1;
      color: white;
      font-weight: 700;
      border: none;
    }

    .btn-secondary {
      padding: 14px 28px;
      border-radius: 999px;
      background: transparent;
      border: 1px solid #475569;
      color: white;
      text-decoration: none;
      font-weight: 700;
    }
`];
